const text = $json.data || "";
const fileName = $('Webhook').item.binary.data.fileName || "unknown.pdf";

return {
  extracted_text: text,
  file_name: fileName
};

function normalizeText(value) {
  return String(value || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();
}

function isUnclassifiedProfile(title) {
  const normalized = normalizeText(title);
  return !normalized || /profil\s+non\s+class/.test(normalized);
}

function inferProfileTitle(data) {
  const source = normalizeText([
    data.profileTitle,
    Array.isArray(data.skills) ? data.skills.join(" ") : data.skills,
    data.education,
    data.summary,
  ].join(" "));

  const rules = [
    { label: "Data Scientist", pattern: /data scientist|scientifique.*donnees|science.*donnees|data science|machine learning|deep learning|python|pandas|tensorflow|pytorch|scikit/ },
    { label: "Data Analyst", pattern: /data analyst|analyste.*donnees|analyse.*donnees|business intelligence|\bbi\b|power bi|tableau|dashboard|kpi|sql/ },
    { label: "Ing?nieur IA", pattern: /ingenieur.*ia|ingenieur.*intelligence artificielle|ai engineer|ml engineer|intelligence artificielle|\bia\b|\bai\b/ },
    { label: "Ing?nieur Cloud / DevOps", pattern: /cloud|devops|infrastructure|kubernetes|docker|aws|azure|gcp|terraform|ci\/cd/ },
    { label: "D?veloppeur Frontend", pattern: /frontend|front-end|react|javascript|typescript|html|css|redux|tailwind/ },
    { label: "D?veloppeur Backend", pattern: /backend|back-end|node|express|spring|java|php|laravel|api|rest|mongodb|mysql|postgresql/ },
    { label: "Designer graphique", pattern: /designer graphique|graphiste|graphisme|conception visuelle|direction artistique|identite visuelle|branding|illustrator|photoshop|indesign|affiche|print|adobe/ },
    { label: "Designer UX/UI", pattern: /\bux\b|\bui\b|figma|wireframe|prototype|interface|design system|designer ux|designer ui/ },
    { label: "Charg? de communication", pattern: /communication|marketing digital|community manager|social media|reseaux sociaux|creation de contenu|contenu digital|campagne/ },
    { label: "Assistant Finance", pattern: /finance|comptabilite|accounting|audit|controle de gestion/ },
    { label: "Assistant RH", pattern: /ressources humaines|recrutement|\brh\b|\bhr\b|paie/ },
  ];

  const match = rules.find((rule) => rule.pattern.test(source));
  return match ? match.label : "Profil non class?";
}

function canonicalizeProfileTitle(title, data = {}) {
  const rawTitle = String(title || "Profil non class?").trim();
  const normalized = normalizeText(rawTitle);

  if (isUnclassifiedProfile(rawTitle)) return inferProfileTitle(data);
  if (/data scientist|scientifique.*donnees|science.*donnees|data science|machine learning|deep learning/.test(normalized)) return "Data Scientist";
  if (/data analyst|analyste.*donnees|analyse.*donnees|business intelligence|\bbi\b|power bi/.test(normalized)) return "Data Analyst";
  if (/ingenieur.*ia|ingenieur.*intelligence artificielle|ai engineer|ml engineer|intelligence artificielle|\bia\b|\bai\b/.test(normalized)) return "Ing?nieur IA";
  if (/cloud|devops|infrastructure|kubernetes|docker|aws|azure|gcp/.test(normalized)) return "Ing?nieur Cloud / DevOps";
  if (/frontend|front-end|react|javascript|typescript|html|css/.test(normalized)) return "D?veloppeur Frontend";
  if (/backend|back-end|node|express|spring|java|php|laravel|api/.test(normalized)) return "D?veloppeur Backend";
  if (/designer graphique|graphiste|graphisme|conception visuelle|direction artistique|identite visuelle|branding|illustrator|photoshop|indesign|affiche|print/.test(normalized)) return "Designer graphique";
  if (/\bux\b|\bui\b|designer ux|designer ui|figma|wireframe|prototype|interface|design system/.test(normalized)) return "Designer UX/UI";
  if (/charge.*communication|communication|marketing digital|community manager|social media|reseaux sociaux|creation de contenu|contenu digital|campagne/.test(normalized)) return "Charg? de communication";

  return inferProfileTitle(data);
}

let raw = ($json.choices?.[0]?.message?.content || "").trim();
if (!raw) {
  throw new Error("Empty response from HTTP Request1");
}

raw = raw.replace(/```json/g, "").replace(/```/g, "").trim();

const start = raw.indexOf("{");
const end = raw.lastIndexOf("}");

if (start === -1 || end === -1 || end <= start) {
  throw new Error("No valid JSON found in response: " + raw.slice(0, 200));
}

const cleaned = raw.slice(start, end + 1);

let data;

try {
  data = JSON.parse(cleaned);
} catch (error) {
  throw new Error("Invalid JSON format returned by AI");
}

if (!data || typeof data !== "object" || Array.isArray(data)) {
  throw new Error("Invalid JSON object");
}

const allowedFields = ["name", "email", "phone", "skills", "education", "summary", "profileTitle"];

for (const key of Object.keys(data)) {
  if (!allowedFields.includes(key)) {
    delete data[key];
  }
}

if (typeof data.name !== "string") {
  throw new Error("Invalid name");
}

if (data.email && typeof data.email !== "string") {
  throw new Error("Invalid email");
}

if (data.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email)) {
  throw new Error("Invalid email");
}

if (data.phone && typeof data.phone !== "string") {
  data.phone = String(data.phone);
}

if (!Array.isArray(data.skills)) {
  throw new Error("Invalid skills");
}

if (
  data.education &&
  typeof data.education !== "string" &&
  !Array.isArray(data.education)
) {
  data.education = String(data.education);
}

data.name = String(data.name || "").slice(0, 100);
data.email = String(data.email || "").slice(0, 150);
data.phone = String(data.phone || "").slice(0, 50);
data.summary = String(data.summary || "").slice(0, 2000);
data.profileTitle = canonicalizeProfileTitle(data.profileTitle, data);

data.skills = data.skills
  .slice(0, 50)
  .map((skill) => String(skill).slice(0, 100));

if (Array.isArray(data.education)) {
  data.education = data.education
    .slice(0, 20)
    .map((e) => {
      if (typeof e === "string") return e.slice(0, 200);

      if (typeof e === "object" && e !== null) {
        return [e.degree, e.institution, e.university, e.year]
          .filter(Boolean)
          .map((v) => String(v).slice(0, 100))
          .join(" - ");
      }

      return "";
    })
    .filter(Boolean)
    .join(" | ");
} else {
  data.education = String(data.education || "").slice(0, 1000);
}

return {
  timestamp: new Date().toISOString(),
  file_name: $("cvshort").item.json.file_name || "",
  name: data.name,
  email: data.email,
  phone: "'" + data.phone.replace(/\n/g, " ").replace(/\s+/g, " ").trim(),
  skills: data.skills.join(", "),
  education: data.education,
  summary: data.summary,
  profileTitle: data.profileTitle,
};

const t = ($json.extracted_text || "").replace(/\r/g, "");

if (t.trim().length < 40) {
  throw new Error("Texte insuffisant extrait du PDF. Le CV semble scanne ou compose d'images : une etape OCR est requise avant l'analyse IA.");
}

const lines = t.split("\n").map(l => l.trim()).filter(Boolean);

const head = lines.slice(0, 120);

const keywords =
/(profil|comp[ée]tences?|skills?|formation|education|exp[ée]riences?|stage|projet|github|mail|email|t[ée]l|phone|\+212|linkedin|langues?|logiciels?|informatique|outils?|technologies?|frameworks?|bureautique|certifications?|coordonn[ée]es?|contact)/i;

const important = lines.filter(l => keywords.test(l)).slice(0, 250);

const cv_short = [...head, "-----", ...important].join("\n").slice(0, 12000);

return {
  file_name: $json.file_name || "",
  extracted_text: $json.extracted_text || "",
  cv_short
};

