const MAX_FILES = 10;
const MAX_FILE_SIZE_MB = 5;
const MAX_FILE_SIZE_BYTES = MAX_FILE_SIZE_MB * 1024 * 1024;

if (items.length > MAX_FILES) {
  throw new Error(`Nombre maximal de fichiers dépassé. Maximum autorisé : ${MAX_FILES}.`);
}

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binaryData = item.binary?.data;

  if (!binaryData) {
    throw new Error("Aucun fichier reçu.");
  }

  const fileName = binaryData.fileName || "";
  const mimeType = binaryData.mimeType || "";
  let fileSize = binaryData.fileSize || 0;

  if (!fileName.toLowerCase().endsWith(".pdf")) {
    throw new Error("Le fichier doit avoir l'extension .pdf.");
  }

  if (mimeType !== "application/pdf") {
    throw new Error("Le fichier doit être un vrai PDF.");
  }

  if (typeof fileSize === "string") {
    const match = fileSize.match(/^([\d.]+)\s*(B|KB|MB|GB)?$/i);

    if (!match) {
      throw new Error("Impossible de lire la taille du fichier.");
    }

    const value = parseFloat(match[1]);
    const unit = (match[2] || "B").toUpperCase();

    if (unit === "KB") fileSize = value * 1024;
    else if (unit === "MB") fileSize = value * 1024 * 1024;
    else if (unit === "GB") fileSize = value * 1024 * 1024 * 1024;
    else fileSize = value;
  }

  if (Number.isNaN(fileSize)) {
    throw new Error("Taille du fichier invalide.");
  }

  if (fileSize === 0) {
    throw new Error("Le fichier est vide.");
  }

  if (fileSize > MAX_FILE_SIZE_BYTES) {
    throw new Error(
      `Le fichier dépasse la taille maximale autorisée de ${MAX_FILE_SIZE_MB} Mo.`
    );
  }

  const buffer = await this.helpers.getBinaryDataBuffer(i, "data");
  const firstBytes = buffer.subarray(0, 1024).toString("latin1");

  if (!firstBytes.includes("%PDF-")) {
    throw new Error("Le fichier n'est pas un vrai PDF valide.");
  }
}

return items;
